	(3, 'Daily Production', 5, 3, 4, NULL, 'production', 'please produce', NULL, 'Normal', 'Assigned', '2026-04-23 18:33:08', '2026-04-23 15:30:00', 'Low', 'Internal', NULL, 0, '2026-05-06 18:41:44', 3, 3, 'Administrative', 1, NULL, '2026-05-06 18:41:44', NULL, NULL, NULL, NULL),
	(4, 'Report Preparation', 15, 12, 13, NULL, 'Prepare report', 'please submit report', NULL, 'Normal', 'Assigned', '2026-04-23 19:11:43', '2026-04-23 16:02:00', 'Low', 'Internal', NULL, 0, '2026-04-23 19:11:43', 12, 12, 'Manpower', 1, NULL, NULL, NULL, NULL, NULL, NULL),
	(5, 'Quality Check', 5, 3, 4, NULL, 'cheke it', 'please check production quality', NULL, 'Normal', 'Assigned', '2026-04-23 19:16:33', '2026-04-23 16:15:00', 'Low', 'Internal', NULL, 0, '2026-04-23 19:16:33', 3, 3, 'Manpower', 1, NULL, NULL, NULL, NULL, NULL, NULL),
	(6, 'Daily Production', 5, 3, 7, NULL, 'ጋርመንት ስራ', 'ይህን ስራ ለጥዋት ፈረቃመሪ እንዲሰጥ ይሁን', NULL, 'Normal', 'Assigned', '2026-04-30 12:52:03', '2026-05-01 15:51:00', 'Low', 'Internal', NULL, 0, '2026-04-30 12:52:07', NULL, 3, 'Maintenance', 1, NULL, NULL, NULL, NULL, NULL, NULL),
	(7, 'Daily Production', 7, 3, 4, 7, 'ጋርመንት ስራ', 'ይህን ስራ በግባቡ እንድታስተባብር ስለመጠየቅ\r\nይህን በዛረው እለት ከ1000ኪሎ ግራም በላይ የሆነ ለጋርመንት ስራ የተረከባችሁትን ጥሬ እቃ በነገ ጥዋት ፈረቃችሁ ጨርሳችሁ እንድታስረክቡ', NULL, 'Normal', 'Assigned', '2026-05-01 21:47:36', '2026-05-03 00:47:00', 'Low', 'Internal', NULL, 0, '2026-05-01 21:55:56', 3, 3, 'Maintenance', 1, 'ጋርመንት ስራ', '2026-05-01 21:49:18', NULL, 'ይህን ስራ በግባቡ እንድታስተባብር ስለመጠየቅ\r\nይህን በዛረው እለት ከ1000ኪሎ ግራም በላይ የሆነ ለጋርመንት ስራ የተረከባችሁትን ጥሬ እቃ በነገ ጥዋት ፈረቃችሁ ጨርሳችሁ እንድታስረክቡ', '2026-05-03 00:47:00', 7),
	(8, 'Maintenance', 7, 3, 8, 7, 'ጋርመንት ማሽን', 'የጋርመንት ማሽን ቁጥር 2 ላይ ብልሽት አጋጥሞናል እና በአስቸኳይ ጥገና ስራ እንድትሰሩልን', NULL, 'Emergency', 'Assigned', '2026-05-02 17:56:30', NULL, 'Low', 'Internal', NULL, 0, '2026-05-06 20:33:23', 3, 3, 'Maintenance', 1, 'ጋርመንት ማሽን', '2026-05-02 18:50:28', NULL, 'የጋርመንት ማሽን ቁጥር 2 ላይ ብልሽት አጋጥሞናል እና በአስቸኳይ ጥገና ስራ እንድትሰሩልን', NULL, 7),
	(9, 'Maintenance', 7, 3, 8, 7, 'ጋርመንት ማሽን', 'ጋርመንት ማሽን ቅጥር 7 የመዘግየት ችግር ገጥሞናል እና እንድታስተካክልሉን', NULL, 'Normal', 'Assigned', '2026-05-02 18:02:57', NULL, 'Low', 'Internal', NULL, 0, '2026-05-06 20:33:23', 3, 3, 'Maintenance', 1, 'ጋርመንት ማሽን', '2026-05-02 18:50:14', NULL, 'ጋርመንት ማሽን ቅጥር 7 የመዘግየት ችግር ገጥሞናል እና እንድታስተካክልሉን', NULL, 7),
	(10, 'Daily Production', 7, 3, 4, 7, 'Daily Garment production', 'For all Employees for each tomorrow do the following in morning Shift\r\n 1. each machine worker produce 100 kg production \r\n2. each employee must announce thier work is complete? \r\n3. control and save there worker(labor/other that is support of there work inside them) and send that what hapen on the work', NULL, 'Normal', 'Assigned', '2026-05-04 21:03:27', '2026-05-06 00:03:00', 'Low', 'Internal', NULL, 0, '2026-05-06 20:33:23', 3, 3, 'Maintenance', 1, 'Daily Garment production', '2026-05-06 18:41:35', NULL, 'For all Employees for each tomorrow do the following in morning Shift\r\n 1. each machine worker produce 100 kg production \r\n2. each employee must announce thier work is complete? \r\n3. control and save there worker(labor/other that is support of there work inside them) and send that what hapen on the work', '2026-05-06 00:03:00', 7),
	(11, 'Daily Production', 7, 3, 4, 7, 'Production of 5,000 Cotton T-Shirts (Batch #CT-2026-051)', 'Produce 5,000 high-quality cotton T-shirts based on the approved design specifications and size breakdown (S, M, L, XL).\r\nThe process should include:\r\nFabric cutting according to patterns\r\nStitching and assembly\r\nQuality inspection at each stage\r\nPrinting of brand logo (front side)\r\nFinal finishing and packaging\r\nEnsure compliance with company quality standards and production efficiency targets. Any defects above acceptable tolerance must be reported immediately to the Quality Control unit.', 'ESCALATED: please do complete fully', 'High', 'In Progress', '2026-05-05 07:28:39', '2026-05-12 10:28:00', 'Low', 'Internal', NULL, 0, '2026-05-08 20:32:27', 3, 3, 'Maintenance', 1, 'Production of 5,000 Cotton T-Shirts (Batch #CT-2026-051)', '2026-05-05 07:52:36', NULL, 'Produce 5,000 high-quality cotton T-shirts based on the approved design specifications and size breakdown (S, M, L, XL).\r\nThe process should include:\r\nFabric cutting according to patterns\r\nStitching and assembly\r\nQuality inspection at each stage\r\nPrinting of brand logo (front side)\r\nFinal finishing and packaging\r\nEnsure compliance with company quality standards and production efficiency targets. Any defects above acceptable tolerance must be reported immediately to the Quality Control unit.', '2026-05-12 10:28:00', 7);
